160→/// Generate a random array with bounded length, biased toward small sizes.
161→///
162→/// Most real bugs appear at boundary lengths (0, 1, 2, 3), so we heavily
163→/// favor those over larger sizes. The distribution:
164→/// - 25% chance of length 0 (empty array)
165→/// - 25% chance of length 1 (single element)
166→/// - 20% chance of length 2
167→/// - 15% chance of length 3
168→/// - 15% chance of length 4-5 (larger arrays, less common in bug-triggering)
169→fn generate_array(
170→    element: &TypeInfo,
171→    rng: &mut impl Rng,
172→    caps: Option<&FrontendCapabilities>,
173→) -> Value {
174→    let len = generate_bounded_array_length(rng);
175→    let items: Vec<Value> = (0..len)
176→        .map(|_| generate_random_value(element, rng, caps))
177→        .collect();
178→    json!(items)
179→}
180→
181→/// Generate an array length biased toward small boundary values (0-3).
182→fn generate_bounded_array_length(rng: &mut impl Rng) -> usize {
183→    let choice: u8 = rng.random_range(0..20);
184→    match choice {
185→        0..5 => 0,   // 25%: empty
186→        5..10 => 1,  // 25%: single element
187→        10..14 => 2, // 20%: two elements
188→        14..17 => 3, // 15%: three elements
189→        _ => rng.random_range(4..=5), // 15%: larger
190→    }
191→}
