218→/// Scope-aware path hash that collapses repeated loop/call scopes.
219→///
220→/// Parses the flat trace into a tree of nested scopes, then for each scope_id
221→/// that appears multiple times at the same nesting level, collapses all
222→/// repetitions to a single sorted set of unique `(branch_id, taken)` pairs.
223→/// When `buckets` is non-empty, each distinct profile is also paired with
224→/// its iteration-count bucket so that different iteration counts produce
225→/// different hashes.
226→fn scope_aware_hash(events: &[crate::execution_record::TraceEvent], buckets: &LoopBuckets) -> u64 {
227→    use crate::execution_record::{ScopeEvent, TraceEvent};
228→    use std::collections::BTreeSet;
229→
230→    /// Discriminant tag for scope enter/exit matching.
231→    #[derive(Clone, Copy, PartialEq)]
232→    enum ScopeKind {
233→        Loop(u32),
234→        Call(u32),
235→    }
236→
237→    /// A sorted branch profile from one loop/call iteration.
238→    type BranchProfile = Vec<(u32, bool)>;
239→
240→    /// A profile paired with its optional iteration-count bucket.
241→    type ProfileWithBucket = (BranchProfile, Option<u32>);
242→
243→    /// Collapsed representation of a scope's content for hashing.
244→    #[derive(Hash)]
245→    enum CollapsedItem {
246→        /// A branch decision outside any scope at this level.
247→        Branch { branch_id: u32, taken: bool },
248→        /// A collapsed scope: set of distinct per-iteration branch profiles,
249→        /// each paired with its iteration-count bucket (or `None` when
250→        /// bucketing is disabled, preserving backward-compat hashing).
251→        Scope { scope_tag: u64, profile_buckets: Vec<ProfileWithBucket> },
252→    }
253→
254→    fn is_matching_exit(event: &TraceEvent, kind: ScopeKind) -> bool {
255→        match (kind, event) {
256→            (ScopeKind::Loop(id), TraceEvent::Scope { event: ScopeEvent::LoopExit { loop_id } }) => *loop_id == id,
257→            (ScopeKind::Call(id), TraceEvent::Scope { event: ScopeEvent::CallExit { call_site_id } }) => *call_site_id == id,
258→            _ => false,
259→        }
260→    }
261→
262→    /// Convert accumulated per-scope profile maps into `CollapsedItem::Scope`
263→    /// entries appended to `items`. Called at both the normal end of `collapse()`
264→    /// and the early return on parent-scope exit — without this, nested scopes
265→    /// would be invisible to their parent's branch profile.
266→    fn emit_scope_items(
267→        items: &mut Vec<CollapsedItem>,
268→        loop_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
269→        call_profiles: &HashMap<u32, HashMap<BranchProfile, u32>>,
270→        buckets: &LoopBuckets,
271→    ) {
272→        let mut scope_ids: Vec<(u64, Vec<ProfileWithBucket>)> = Vec::new();
273→        for (id, profiles) in loop_profiles {
274→            let tag = (*id as u64) | (1u64 << 32);
275→            let mut sorted: Vec<ProfileWithBucket> = profiles
276→                .iter()
277→                .map(|(profile, &count)| {
278→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
279→                    (profile.clone(), bucket)
280→                })
281→                .collect();
282→            sorted.sort();
283→            scope_ids.push((tag, sorted));
284→        }
285→        for (id, profiles) in call_profiles {
286→            let tag = (*id as u64) | (2u64 << 32);
287→            let mut sorted: Vec<ProfileWithBucket> = profiles
288→                .iter()
289→                .map(|(profile, &count)| {
290→                    let bucket = if buckets.is_disabled() { None } else { Some(buckets.bucket(count)) };
291→                    (profile.clone(), bucket)
292→                })
293→                .collect();
294→            sorted.sort();
295→            scope_ids.push((tag, sorted));
296→        }
297→        scope_ids.sort_by_key(|(tag, _)| *tag);
298→        for (scope_tag, profile_buckets) in scope_ids {
299→            items.push(CollapsedItem::Scope { scope_tag, profile_buckets });
300→        }
301→    }
302→
303→    fn collapse(events: &[TraceEvent], buckets: &LoopBuckets) -> (Vec<CollapsedItem>, usize) {
304→        let mut items: Vec<CollapsedItem> = Vec::new();
305→        let mut loop_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
306→        let mut call_profiles: HashMap<u32, HashMap<BranchProfile, u32>> = HashMap::new();
307→
308→        let mut i = 0;
309→        while i < events.len() {
310→            match &events[i] {
311→                TraceEvent::Branch { decision } => {
312→                    items.push(CollapsedItem::Branch {
313→                        branch_id: decision.branch_id,
314→                        taken: decision.taken,
315→                    });
316→                    i += 1;
317→                }
318→                TraceEvent::Scope { event } => {
319→                    let (kind, is_enter) = match event {
320→                        ScopeEvent::LoopEnter { loop_id } => (ScopeKind::Loop(*loop_id), true),
321→                        ScopeEvent::LoopExit { loop_id } => (ScopeKind::Loop(*loop_id), false),
322→                        ScopeEvent::CallEnter { call_site_id } => (ScopeKind::Call(*call_site_id), true),
323→                        ScopeEvent::CallExit { call_site_id } => (ScopeKind::Call(*call_site_id), false),
324→                    };
325→
326→                    if !is_enter {
327→                        // Exit without matching enter — we've hit the boundary
328→                        // of our parent scope. Emit accumulated scope items
329→                        // before returning so nested scopes are visible to
330→                        // the parent's branch profile.
331→                        emit_scope_items(&mut items, &loop_profiles, &call_profiles, buckets);
332→                        return (items, i);
333→                    }
334→
335→                    // Recursively collapse the scope body
336→                    let body_start = i + 1;
337→                    let (child_items, consumed) = collapse(&events[body_start..], buckets);
338→                    let body_end = body_start + consumed;
339→
340→                    // Build this iteration's branch profile (sorted for determinism)
341→                    let mut profile = BTreeSet::new();
342→                    for item in &child_items {
343→                        match item {
344→                            CollapsedItem::Branch { branch_id, taken } => {
345→                                profile.insert((*branch_id, *taken));
346→                            }
347→                            CollapsedItem::Scope { scope_tag, profile_buckets } => {
348→                                let mut h = DefaultHasher::new();
349→                                scope_tag.hash(&mut h);
350→                                profile_buckets.hash(&mut h);
351→                                let synthetic_id = (h.finish() & 0x7FFF_FFFF) as u32 | 0x8000_0000;
352→                                profile.insert((synthetic_id, true));
353→                            }
354→                        }
355→                    }
356→                    let profile_vec: Vec<(u32, bool)> = profile.into_iter().collect();
357→
358→                    // Increment iteration count for this (scope_id, profile) pair
359→                    match kind {
360→                        ScopeKind::Loop(id) => {
361→                            *loop_profiles.entry(id).or_default().entry(profile_vec).or_insert(0) += 1;
362→                        }
363→                        ScopeKind::Call(id) => {
364→                            *call_profiles.entry(id).or_default().entry(profile_vec).or_insert(0) += 1;
365→                        }
366→                    }
367→
368→                    // Skip past the exit event if present
369→                    i = body_end;
370→                    if i < events.len() && is_matching_exit(&events[i], kind) {
371→                        i += 1;
372→                    }
373→                }
374→            }
375→        }
376→
377→        emit_scope_items(&mut items, &loop_profiles, &call_profiles, buckets);
378→        (items, events.len())
379→    }
380→
381→    let (items, _) = collapse(events, buckets);
382→    let mut hasher = DefaultHasher::new();
383→    for item in &items {
384→        item.hash(&mut hasher);
385→    }
386→    hasher.finish()
387→}
