389→/// Confidence-scored label for error intent classification.
390→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
391→pub struct ErrorIntentLabel {
392→    /// "likely_validation", "likely_runtime", or "unknown"
393→    pub label: String,
394→    /// Confidence score 0.0–1.0
395→    pub confidence: f64,
396→}
397→
398→/// Classify whether a thrown error is a deliberate validation rejection or an
399→/// accidental runtime failure by examining the branch path immediately before the error.
400→///
401→/// Pattern: a guard branch taken=true followed immediately by the error (no intervening
402→/// branches) suggests intentional input rejection. Errors without a preceding guard
403→/// or deep in the branch path are more likely accidental.
404→pub fn classify_error_intent(result: &crate::protocol::ExecuteResult) -> Option<ErrorIntentLabel> {
405→    let error = result.thrown_error.as_ref()?;
406→
407→    // If the frontend already classified this as infrastructure, trust it
408→    if error.error_category.as_deref() == Some("infrastructure") {
409→        return Some(ErrorIntentLabel {
410→            label: "likely_runtime".into(),
411→            confidence: 0.9,
412→        });
413→    }
414→
415→    let branch_path = &result.branch_path;
416→    if branch_path.is_empty() {
417→        // No branch data — can't infer intent
418→        return Some(ErrorIntentLabel {
419→            label: "unknown".into(),
420→            confidence: 0.0,
421→        });
422→    }
423→
424→    // Check the last branch before the error
425→    let last_branch = branch_path.last().unwrap();
426→
427→    // Guard pattern: last branch taken=true, suggesting an if-guard that led to a throw.
428→    // Shallow depth (few branches) + guard = likely validation.
429→    if last_branch.taken && branch_path.len() <= 3 {
430→        return Some(ErrorIntentLabel {
431→            label: "likely_validation".into(),
432→            confidence: 0.7,
433→        });
434→    }
435→
436→    // Deep branch path with error = likely accidental runtime failure
437→    if branch_path.len() > 5 {
438→        return Some(ErrorIntentLabel {
439→            label: "likely_runtime".into(),
440→            confidence: 0.6,
441→        });
442→    }
443→
444→    // Frontend-level classification can help disambiguate
445→    if error.error_category.as_deref() == Some("validation") {
446→        return Some(ErrorIntentLabel {
447→            label: "likely_validation".into(),
448→            confidence: 0.8,
449→        });
450→    }
451→    if error.error_category.as_deref() == Some("runtime") {
452→        return Some(ErrorIntentLabel {
453→            label: "likely_runtime".into(),
454→            confidence: 0.7,
455→        });
456→    }
457→
458→    Some(ErrorIntentLabel {
459→        label: "unknown".into(),
460→        confidence: 0.3,
461→    })
462→}
