469→/// Send a Setup command to the frontend and return a `SetupContextStack`
470→/// containing the returned context at the given level.
471→pub(crate) async fn send_setup(
472→    frontend: &mut Frontend,
473→    setup_file: &str,
474→    scope: &str,
475→    level: SetupLevel,
476→    project_root: Option<String>,
477→) -> Result<Option<SetupContextStack>, ExploreError> {
478→    let response = frontend
479→        .send(ProtoCommand::Setup {
480→            file: setup_file.to_string(),
481→            scope: scope.to_string(),
482→            level,
483→            project_root,
484→            parent_context: None,
485→        })
486→        .await?;
487→    match response.result {
488→        ResponseResult::Setup { setup_context } => Ok(Some(SetupContextStack {
489→            contexts: vec![SetupContextEntry {
490→                level,
491→                context: setup_context,
492→            }],
493→        })),
494→        ResponseResult::Error { message, .. } => {
495→            log::warn!("setup error for {scope}: {message}");
496→            Ok(None)
497→        }
498→        other => Err(ExploreError::UnexpectedResponse(format!(
499→            "expected Setup response, got {other:?}"
500→        ))),
501→    }
502→}
