524→/// Explore a single function by generating random inputs and executing them.
525→pub async fn explore_function(
526→    frontend: &mut Frontend,
527→    analysis: &FunctionAnalysis,
528→    config: &ExploreConfig,
529→) -> Result<ObservationOutput, ExploreError> {
530→    let instrument_response = frontend
531→        .send(ProtoCommand::Instrument {
532→            file: config.file.clone(),
533→            function: analysis.name.clone(),
534→            mocks: config.mocks.clone(),
535→            project_root: config.project_root.clone(),
536→        })
537→        .await?;
538→
539→    let instrumentable_line_count = match instrument_response.result {
540→        ResponseResult::Instrument { instrumented, instrumentable_line_count, .. } => {
541→            if !instrumented {
542→                return Err(ExploreError::UnexpectedResponse(
543→                    "instrumentation returned instrumented=false".to_string(),
544→                ));
545→            }
546→            instrumentable_line_count
547→        }
548→        ResponseResult::Error { code, message, .. } => {
549→            return Err(ExploreError::UnexpectedResponse(format!(
550→                "instrument error ({code:?}): {message}"
551→            )));
552→        }
553→        other => {
554→            return Err(ExploreError::UnexpectedResponse(format!(
555→                "expected Instrument response, got {other:?}"
556→            )));
557→        }
558→    };
559→
560→    let mut rng = match config.seed {
561→        Some(seed) => StdRng::seed_from_u64(seed),
562→        None => StdRng::from_os_rng(),
563→    };
564→
565→    // --- Setup lifecycle ---
566→    let has_setup =
567→        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
568→    let per_function_setup = has_setup && config.setup_level == SetupLevel::Function;
569→    let per_execution_setup = has_setup && config.setup_level == SetupLevel::Execution;
570→
571→    let mut setup_context: Option<SetupContextStack> = None;
572→
573→    if per_function_setup
574→        && let Some(ref setup_file) = config.setup_file
